/* 
 * Simple, 32-bit and 64-bit clean allocator based on an implicit free list,
 * first fit placement, and boundary tag coalescing, as described in the
 * CS:APP3e text.  Blocks are aligned to double-word boundaries.  This
 * yields 8-byte aligned blocks on a 32-bit processor, and 16-byte aligned
 * blocks on a 64-bit processor.  However, 16-byte alignment is stricter
 * than necessary; the assignment only requires 8-byte alignment.  The
 * minimum block size is four words.
 *
 * This allocator uses the size of a pointer, e.g., sizeof(void *), to
 * define the size of a word.  This allocator also uses the standard
 * type uintptr_t to define unsigned integers that are the same size
 * as a pointer, i.e., sizeof(uintptr_t) == sizeof(void *).
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

/*********************************************************
 * NOTE TO STUDENTS: Before you do anything else, please
 * provide your team information in the following struct.
 ********************************************************/
team_t team = {
	/* Team name */
	"BSCS Bench",
	/* First member's full name */
	"BSCS Bench Agent",
	/* First member's NetID */
	"bscs1",
	/* Second member's full name (leave blank if none) */
	"",
	/* Second member's NetID (leave blank if none) */
	""
};

/* Basic constants and macros: */
#define WSIZE      sizeof(void *) /* Word and header/footer size (bytes) */
#define DSIZE      (2 * WSIZE)    /* Doubleword size (bytes) */
#define CHUNKSIZE  (1 << 12)      /* Extend heap by this amount (bytes) */

#define MAX(x, y)  ((x) > (y) ? (x) : (y))  

/* Pack a size and allocated bit into a word. */
#define PACK(size, alloc)  ((size) | (alloc))

/* Read and write a word at address p. */
#define GET(p)       (*(uintptr_t *)(p))
#define PUT(p, val)  (*(uintptr_t *)(p) = (val))

/* Read the size and allocated fields from address p. */
#define GET_SIZE(p)   (GET(p) & ~(DSIZE - 1))
#define GET_ALLOC(p)  (GET(p) & 0x1)

/* Given block ptr bp, compute address of its header and footer. */
#define HDRP(bp)  ((char *)(bp) - WSIZE)
#define FTRP(bp)  ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Given block ptr bp, compute address of next and previous blocks. */
#define NEXT_BLKP(bp)  ((char *)(bp) + GET_SIZE(((char *)(bp) - WSIZE)))
#define PREV_BLKP(bp)  ((char *)(bp) - GET_SIZE(((char *)(bp) - DSIZE)))

/* Global variables: */
static char *heap_listp;     /* Pointer to first block */
static void *free_lists[16]; /* Array of segregated free lists */

/* Macros for free list management */
#define PRED_PTR(p) (*(void **)(p))
#define SUCC_PTR(p) (*(void **)((char *)(p) + WSIZE))
#define SET_PRED_PTR(p, ptr) (PRED_PTR(p) = (ptr))
#define SET_SUCC_PTR(p, ptr) (SUCC_PTR(p) = (ptr))

/* Function prototypes for internal helper routines: */
static void *coalesce(void *bp);
static void *extend_heap(size_t words);
static void *find_fit(size_t asize);
static void place(void *bp, size_t asize);
static int get_free_list_index(size_t size);
static void add_to_free_list(void *bp);
static void remove_from_free_list(void *bp);

/* Function prototypes for heap consistency checker routines: */
static void checkblock(void *bp);
static void checkheap(bool verbose);
static void printblock(void *bp); 

/* 
 * Requires:
 *   None.
 *
 * Effects:
 *   Initialize the memory manager.  Returns 0 if the memory manager was
 *   successfully initialized and -1 otherwise.
 */
int
mm_init(void)
{
	int i;

	/* Initialize free lists */
	for (i = 0; i < 16; i++)
		free_lists[i] = NULL;

	/* Create the initial empty heap. */
	if ((heap_listp = mem_sbrk(4 * WSIZE)) == (void *)-1)
		return (-1);
	PUT(heap_listp, 0);                            /* Alignment padding */
	PUT(heap_listp + (1 * WSIZE), PACK(DSIZE, 1)); /* Prologue header */
	PUT(heap_listp + (2 * WSIZE), PACK(DSIZE, 1)); /* Prologue footer */
	PUT(heap_listp + (3 * WSIZE), PACK(0, 1));     /* Epilogue header */
	heap_listp += (2 * WSIZE);

	/* Extend the empty heap with a free block of CHUNKSIZE bytes. */
	if (extend_heap(CHUNKSIZE / WSIZE) == NULL)
		return (-1);
	return (0);
}

/* 
 * Requires:
 *   None.
 *
 * Effects:
 *   Allocate a block with at least "size" bytes of payload, unless "size" is
 *   zero.  Returns the address of this block if the allocation was successful
 *   and NULL otherwise.
 */
void *
mm_malloc(size_t size) 
{
	size_t asize;      /* Adjusted block size */
	size_t extendsize; /* Amount to extend heap if no fit */
	void *bp;

	/* Ignore spurious requests. */
	if (size == 0)
		return (NULL);

	/* Adjust block size to include overhead and alignment reqs. */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	/* Search the free list for a fit. */
	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return (bp);
	}

	/* No fit found.  Get more memory and place the block. */
	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize / WSIZE)) == NULL)  
		return (NULL);
	place(bp, asize);
	return (bp);
} 

/* 
 * Requires:
 *   "bp" is either the address of an allocated block or NULL.
 *
 * Effects:
 *   Free a block.
 */
void
mm_free(void *bp)
{
	size_t size;

	/* Ignore spurious requests. */
	if (bp == NULL)
		return;

	/* Free and coalesce the block. */
	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	coalesce(bp);
}

/*
 * Requires:
 *   "ptr" is either the address of an allocated block or NULL.
 *
 * Effects:
 *   Reallocates the block "ptr" to a block with at least "size" bytes of
 *   payload, unless "size" is zero.  If "size" is zero, frees the block
 *   "ptr" and returns NULL.  If the block "ptr" is already a block with at
 *   least "size" bytes of payload, then "ptr" may optionally be returned.
 *   Otherwise, a new block is allocated and the contents of the old block
 *   "ptr" are copied to that new block.  Returns the address of this new
 *   block if the allocation was successful and NULL otherwise.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t oldsize, asize;
	void *newptr;
	void *next_bp;

	/* If size == 0 then this is just free, and we return NULL. */
	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}

	/* If oldptr is NULL, then this is just malloc. */
	if (ptr == NULL)
		return (mm_malloc(size));

	/* Get the adjusted size */
	if (size <= DSIZE)
		asize = 2 * DSIZE;
	else
		asize = DSIZE * ((size + DSIZE + (DSIZE - 1)) / DSIZE);

	oldsize = GET_SIZE(HDRP(ptr));

	/* If the requested size fits in the current block, return ptr */
	if (asize <= oldsize) {
		/* Optionally split if there's enough space */
		if ((oldsize - asize) >= (2 * DSIZE)) {
			PUT(HDRP(ptr), PACK(asize, 1));
			PUT(FTRP(ptr), PACK(asize, 1));
			void *remainder = NEXT_BLKP(ptr);
			PUT(HDRP(remainder), PACK(oldsize - asize, 0));
			PUT(FTRP(remainder), PACK(oldsize - asize, 0));
			coalesce(remainder);
		}
		return (ptr);
	}

	/* Check if next block is free and can accommodate the expansion */
	next_bp = NEXT_BLKP(ptr);
	if (!GET_ALLOC(HDRP(next_bp)) && (asize <= oldsize + GET_SIZE(HDRP(next_bp)))) {
		size_t next_size = GET_SIZE(HDRP(next_bp));
		remove_from_free_list(next_bp);
		PUT(HDRP(ptr), PACK(asize, 1));
		PUT(FTRP(ptr), PACK(asize, 1));

		if ((oldsize + next_size - asize) >= (2 * DSIZE)) {
			void *remainder = NEXT_BLKP(ptr);
			PUT(HDRP(remainder), PACK(oldsize + next_size - asize, 0));
			PUT(FTRP(remainder), PACK(oldsize + next_size - asize, 0));
			add_to_free_list(remainder);
		} else {
			PUT(HDRP(ptr), PACK(oldsize + next_size, 1));
			PUT(FTRP(ptr), PACK(oldsize + next_size, 1));
		}
		return (ptr);
	}

	/* Allocate a new block and copy the data */
	newptr = mm_malloc(size);

	/* If realloc() fails, the original block is left untouched. */
	if (newptr == NULL)
		return (NULL);

	/* Copy just the old data, not the old header and footer. */
	size_t copysize = oldsize - DSIZE;
	if (size < copysize)
		copysize = size;
	memcpy(newptr, ptr, copysize);

	/* Free the old block. */
	mm_free(ptr);

	return (newptr);
}

/*
 * The following routines are internal helper routines.
 */

/*
 * Requires:
 *   "bp" is the address of a newly freed block.
 *
 * Effects:
 *   Perform boundary tag coalescing.  Returns the address of the coalesced
 *   block.
 */
static void *
coalesce(void *bp)
{
	size_t size = GET_SIZE(HDRP(bp));
	bool prev_alloc = GET_ALLOC(FTRP(PREV_BLKP(bp)));
	bool next_alloc = GET_ALLOC(HDRP(NEXT_BLKP(bp)));

	if (prev_alloc && next_alloc) {                 /* Case 1 */
		add_to_free_list(bp);
		return (bp);
	} else if (prev_alloc && !next_alloc) {         /* Case 2 */
		void *next_bp = NEXT_BLKP(bp);
		remove_from_free_list(next_bp);
		size += GET_SIZE(HDRP(next_bp));
		PUT(HDRP(bp), PACK(size, 0));
		PUT(FTRP(bp), PACK(size, 0));
		add_to_free_list(bp);
	} else if (!prev_alloc && next_alloc) {         /* Case 3 */
		void *prev_bp = PREV_BLKP(bp);
		remove_from_free_list(prev_bp);
		size += GET_SIZE(HDRP(prev_bp));
		PUT(FTRP(bp), PACK(size, 0));
		PUT(HDRP(prev_bp), PACK(size, 0));
		bp = prev_bp;
		add_to_free_list(bp);
	} else {                                        /* Case 4 */
		void *prev_bp = PREV_BLKP(bp);
		void *next_bp = NEXT_BLKP(bp);
		remove_from_free_list(prev_bp);
		remove_from_free_list(next_bp);
		size += GET_SIZE(HDRP(prev_bp)) +
		    GET_SIZE(HDRP(next_bp));
		PUT(HDRP(prev_bp), PACK(size, 0));
		PUT(FTRP(next_bp), PACK(size, 0));
		bp = prev_bp;
		add_to_free_list(bp);
	}
	return (bp);
}

/* 
 * Requires:
 *   None.
 *
 * Effects:
 *   Extend the heap with a free block and return that block's address.
 */
static void *
extend_heap(size_t words) 
{
	size_t size;
	void *bp;

	/* Allocate an even number of words to maintain alignment. */
	size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
	if ((bp = mem_sbrk(size)) == (void *)-1)  
		return (NULL);

	/* Initialize free block header/footer and the epilogue header. */
	PUT(HDRP(bp), PACK(size, 0));         /* Free block header */
	PUT(FTRP(bp), PACK(size, 0));         /* Free block footer */
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1)); /* New epilogue header */

	/* Coalesce if the previous block was free. */
	return (coalesce(bp));
}

/*
 * Requires:
 *   None.
 *
 * Effects:
 *   Find a best fit for a block with "asize" bytes.  Returns that block's address
 *   or NULL if no suitable block was found.
 */
static void *
find_fit(size_t asize)
{
	int index = get_free_list_index(asize);
	void *bp;
	void *best = NULL;
	size_t best_size = -1UL;

	/* Search for best fit in the appropriate free list and larger lists */
	for (; index < 16; index++) {
		bp = free_lists[index];
		while (bp != NULL) {
			size_t bp_size = GET_SIZE(HDRP(bp));
			if (asize <= bp_size && bp_size < best_size) {
				best = bp;
				best_size = bp_size;
				/* For tight fits, stop looking */
				if (best_size == asize || best_size < (asize + 2 * DSIZE))
					return (best);
			}
			bp = SUCC_PTR(bp);
		}
	}
	return (best);
}

/*
 * Requires:
 *   "bp" is the address of a free block that is at least "asize" bytes.
 *
 * Effects:
 *   Place a block of "asize" bytes at the start of the free block "bp" and
 *   split that block if the remainder would be at least the minimum block
 *   size.
 */
static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));

	remove_from_free_list(bp);
	if ((csize - asize) >= (2 * DSIZE)) {
		PUT(HDRP(bp), PACK(asize, 1));
		PUT(FTRP(bp), PACK(asize, 1));
		void *remainder = NEXT_BLKP(bp);
		PUT(HDRP(remainder), PACK(csize - asize, 0));
		PUT(FTRP(remainder), PACK(csize - asize, 0));
		add_to_free_list(remainder);
	} else {
		PUT(HDRP(bp), PACK(csize, 1));
		PUT(FTRP(bp), PACK(csize, 1));
	}
}

/*
 * Return index of free list for a given block size.
 */
static int
get_free_list_index(size_t size)
{
	if (size <= 32)
		return 0;
	else if (size <= 64)
		return 1;
	else if (size <= 128)
		return 2;
	else if (size <= 256)
		return 3;
	else if (size <= 512)
		return 4;
	else if (size <= 1024)
		return 5;
	else if (size <= 2048)
		return 6;
	else if (size <= 4096)
		return 7;
	else if (size <= 8192)
		return 8;
	else if (size <= 16384)
		return 9;
	else if (size <= 32768)
		return 10;
	else if (size <= 65536)
		return 11;
	else if (size <= 131072)
		return 12;
	else if (size <= 262144)
		return 13;
	else if (size <= 524288)
		return 14;
	else
		return 15;
}

/*
 * Add block bp to the free list.
 */
static void
add_to_free_list(void *bp)
{
	int index = get_free_list_index(GET_SIZE(HDRP(bp)));
	void *head = free_lists[index];

	SET_PRED_PTR(bp, NULL);
	SET_SUCC_PTR(bp, head);
	if (head != NULL)
		SET_PRED_PTR(head, bp);
	free_lists[index] = bp;
}

/*
 * Remove block bp from the free list.
 */
static void
remove_from_free_list(void *bp)
{
	int index = get_free_list_index(GET_SIZE(HDRP(bp)));
	void *pred = PRED_PTR(bp);
	void *succ = SUCC_PTR(bp);

	if (pred != NULL)
		SET_SUCC_PTR(pred, succ);
	else
		free_lists[index] = succ;

	if (succ != NULL)
		SET_PRED_PTR(succ, pred);
}

/*
 * The remaining routines are heap consistency checker routines.
 */

/*
 * Requires:
 *   "bp" is the address of a block.
 *
 * Effects:
 *   Perform a minimal check on the block "bp".
 */
static void
checkblock(void *bp) 
{

	if ((uintptr_t)bp % DSIZE)
		printf("Error: %p is not doubleword aligned\n", bp);
	if (GET(HDRP(bp)) != GET(FTRP(bp)))
		printf("Error: header does not match footer\n");
}

/* 
 * Requires:
 *   None.
 *
 * Effects:
 *   Perform a minimal check of the heap for consistency. 
 */
void
checkheap(bool verbose) 
{
	void *bp;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE ||
	    !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");
	checkblock(heap_listp);

	for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);
	}

	if (verbose)
		printblock(bp);
	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");
}

/*
 * Requires:
 *   "bp" is the address of a block.
 *
 * Effects:
 *   Print the block "bp".
 */
static void
printblock(void *bp) 
{
	size_t hsize, fsize;
	bool halloc, falloc;

	checkheap(false);
	hsize = GET_SIZE(HDRP(bp));
	halloc = GET_ALLOC(HDRP(bp));  
	fsize = GET_SIZE(FTRP(bp));
	falloc = GET_ALLOC(FTRP(bp));  

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}

	printf("%p: header: [%zu:%c] footer: [%zu:%c]\n", bp, 
	    hsize, (halloc ? 'a' : 'f'), 
	    fsize, (falloc ? 'a' : 'f'));
}

